import Foundation
struct BatchSettlingAreaEstimateEngine: Sendable { func calculate(_ input: BatchSettlingAreaEstimateInput) throws -> BatchSettlingAreaEstimateResult { let v=[input.slurryVolumetricFlow,input.designSettlingVelocity,input.hydraulicSafetyFactor,input.tankAspectRatio]; guard v.allSatisfy(\.isFinite) else { throw BatchSettlingAreaEstimateError.nonFiniteInput }; guard input.slurryVolumetricFlow>0,input.designSettlingVelocity>0 else { throw BatchSettlingAreaEstimateError.nonPositiveFlowOrVelocity }; guard input.hydraulicSafetyFactor>=1 else { throw BatchSettlingAreaEstimateError.invalidSafetyFactor }; guard input.tankAspectRatio>0 else { throw BatchSettlingAreaEstimateError.nonPositiveAspectRatio }; let at=input.slurryVolumetricFlow/input.designSettlingVelocity; let ad=at*input.hydraulicSafetyFactor; let d=Foundation.sqrt(4*ad/Double.pi); let h=input.tankAspectRatio*d; let vol=ad*h; guard [at,ad,d,h,vol].allSatisfy(\.isFinite),ad>0,vol>0 else { throw BatchSettlingAreaEstimateError.numericalFailure }; return .init(theoreticalArea:at,designArea:ad,equivalentDiameter:d,liquidDepth:h,designVolume:vol,modelName:"Hydraulic overflow-rate settling estimate",limitationDescription:"Uses area equal to volumetric flow divided by design settling velocity for a circular vessel.") } }
